+fn e2e_storm_logger_produces_valid_jsonl() {
+    use ftui_harness::resize_storm::StormLogger;
+
+    let config = StormConfig::default()
+        .with_seed(42)
+        .with_pattern(StormPattern::Burst { count: 10 })
